        self.t2 = Pin(34, Pin.IN)
        self.t3 = Pin(35, Pin.IN)
        self.t4 = Pin(36, Pin.IN)
        self.t5 = Pin(39, Pin.IN)
        
        #红外接收头
        self.IR = Pin(32, Pin.IN)
        
