    #调速
    def setspeed(self,speed):
        self.duty=speed
        if self.s_forward==1:
            self.forward()
        if self.s_backward==1:
            self.backward()
        if self.s_left==1:
            self.turn_left()
        if self.s_right==1:
            self.turn_right()

    # 独立设置四个电机速度 (-1023 到 1023)
    def set_motors(self, m1, m2, m3, m4):
        # M1: 左前
        if m1 >= 0:
            self.M1_P.duty(min(1023, m1))
            self.M1_N.duty(0)
        else:
            self.M1_P.duty(0)
            self.M1_N.duty(min(1023, abs(m1)))
            
        # M2: 右前
        if m2 >= 0:
            self.M2_P.duty(min(1023, m2))
            self.M2_N.duty(0)
        else:
            self.M2_P.duty(0)
            self.M2_N.duty(min(1023, abs(m2)))
            
        # M3: 右后
        if m3 >= 0:
            self.M3_P.duty(min(1023, m3))
            self.M3_N.duty(0)
        else:
            self.M3_P.duty(0)
            self.M3_N.duty(min(1023, abs(m3)))
            
        # M4: 左后
        if m4 >= 0:
            self.M4_P.duty(min(1023, m4))
            self.M4_N.duty(0)
        else:
            self.M4_P.duty(0)
            self.M4_N.duty(min(1023, abs(m4)))

    #前进    
    def forward(self):
        speed=self.duty
        self.s_forward=1
        self.s_backward=0
        self.s_left=0
        self.s_right=0
        
        self.M1_P.duty(speed)
        self.M1_N.duty(0)    
        self.M2_P.duty(speed)
        self.M2_N.duty(0)
        self.M3_P.duty(speed)
        self.M3_N.duty(0)
        self.M4_P.duty(speed)
        self.M4_N.duty(0)
    
    #后退
    def backward(self):
        speed=self.duty
        self.s_forward=0
        self.s_backward=1
        self.s_left=0
        self.s_right=0

        self.M1_P.duty(0)
        self.M1_N.duty(speed)    
        self.M2_P.duty(0)
        self.M2_N.duty(speed)
        self.M3_P.duty(0)
        self.M3_N.duty(speed)
        self.M4_P.duty(0)
        self.M4_N.duty(speed)

    #左转
    def turn_left(self, mode=0):
        speed=self.duty
        self.s_forward=0
        self.s_backward=0
        self.s_left=1
        self.s_right=0
        
        #普通转向
        if mode == 0: 
            self.M1_P.duty(0)
            self.M1_N.duty(0)    
            self.M2_P.duty(speed)
            self.M2_N.duty(0)
            self.M3_P.duty(speed)
            self.M3_N.duty(0)
            self.M4_P.duty(0)
            self.M4_N.duty(0)
        
        #大幅度转向
        elif mode ==1:
            self.M1_P.duty(0)
            self.M1_N.duty(speed)    
            self.M2_P.duty(speed)
            self.M2_N.duty(0)
            self.M3_P.duty(speed)
            self.M3_N.duty(0)
            self.M4_P.duty(0)
            self.M4_N.duty(speed)

    #右转
    def turn_right(self, mode=0):
        speed=self.duty
        self.s_forward=0
        self.s_backward=0
        self.s_left=0
        self.s_right=1
        #普通转向
        if mode == 0:
            self.M1_P.duty(speed)
            self.M1_N.duty(0)    
            self.M2_P.duty(0)
            self.M2_N.duty(0)
            self.M3_P.duty(0)
            self.M3_N.duty(0)
            self.M4_P.duty(speed)
            self.M4_N.duty(0)
        #大幅度转向
        elif mode == 1: 
            self.M1_P.duty(speed)
            self.M1_N.duty(0)    
            self.M2_P.duty(0)
            self.M2_N.duty(speed)
            self.M3_P.duty(0)
            self.M3_N.duty(speed)
            self.M4_P.duty(speed)
            self.M4_N.duty(0)

    #停止
    def stop(self):
        self.s_forward=0
        self.s_backward=0
        self.s_left=0
        self.s_right=0
        self.M1_P.duty(0)
        self.M1_N.duty(0)    
        self.M2_P.duty(0)
        self.M2_N.duty(0)
        self.M3_P.duty(0)
        self.M3_N.duty(0)
        self.M4_P.duty(0)
        self.M4_N.duty(0)

